(async () => {
  console.log(`[${REQUEST_ID}] [START] Worker Logic Activated for Record: ${RECORD_ID}`);
  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY);
  const paths = JSON.parse(IMAGE_PATHS_RAW);

